def eval_bool(expr: str, env: dict) -> bool:
    import re

    def tokenize(s):
        token_pattern = re.compile(
            r'\s*(true|false|not|and|or|&&|\|\||!|\(|\)|[A-Za-z_][A-Za-z0-9_]*)\s*'
        )
        tokens = []
        pos = 0
        while pos < len(s):
            if s[pos].isspace():
                pos += 1
                continue
            m = token_pattern.match(s, pos)
            if not m:
                raise ValueError(f"Unexpected character at position {pos}: {s[pos]!r}")
            tokens.append(m.group(1))
            pos = m.end()
        return tokens

    tokens = tokenize(expr)
    pos = 0

    def peek():
        return tokens[pos] if pos < len(tokens) else None

    def consume():
        nonlocal pos
        t = tokens[pos]
        pos += 1
        return t

    def parse_or():
        left = parse_and()
        while peek() in ('or', '||'):
            consume()
            right = parse_and()
            left = left or right
        return left

    def parse_and():
        left = parse_not()
        while peek() in ('and', '&&'):
            consume()
            right = parse_not()
            left = left and right
        return left

    def parse_not():
        if peek() in ('not', '!'):
            consume()
            return not parse_not()
        return parse_atom()

    def parse_atom():
        nonlocal pos
        t = peek()
        if t is None:
            raise ValueError("Unexpected end of expression")
        if t == '(':
            consume()
            val = parse_or()
            if peek() != ')':
                raise ValueError("Expected closing parenthesis")
            consume()
            return val
        elif t == 'true':
            consume()
            return True
        elif t == 'false':
            consume()
            return False
        elif re.match(r'^[A-Za-z_][A-Za-z0-9_]*$', t) and t not in ('not', 'and', 'or'):
            consume()
            if t not in env:
                raise ValueError(f"Unknown variable: {t!r}")
            return bool(env[t])
        else:
            raise ValueError(f"Unexpected token: {t!r}")

    result = parse_or()
    if pos != len(tokens):
        raise ValueError(f"Unexpected token after expression: {tokens[pos]!r}")
    return result
